import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface Meal {
  mealType: string;
  name: string;
  calories: number;
  prepTimeMinutes: number;
}

interface MealsData {
  mealsToday: Meal[];
  totalCalories: number;
  averagePrepTime: number;
}

export default function Widget() {
  const mealsData = response.data as MealsData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#FF5722' }}>
              Today's Meals
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Total Calories: {mealsData.totalCalories}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Avg. Prep Time: {mealsData.averagePrepTime} mins
            </Typography>
          </Box>

          <Stack spacing={1}>
            {mealsData.mealsToday.map((meal, index) => (
              <Box key={index}>
                <Stack direction="row" justifyContent="space-between" alignItems="center">
                  <Typography variant="body2" fontWeight={500}>
                    {meal.mealType}: {meal.name}
                  </Typography>
                  <Typography variant="caption" color="text.secondary">
                    {meal.calories} cal, {meal.prepTimeMinutes} mins
                  </Typography>
                </Stack>
                <Chip
                  label={meal.mealType}
                  sx={{ fontSize: '10px', bgcolor: '#FFC107', color: '#FFF', mt: 0.5 }}
                />
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
